 public function run():void{$governance=['admin.security.access_review.view','admin.security.access_review.manage','admin.security.access_review.decide','admin.security.reviewer_access.expire','admin.security.reviewer_access.notify_expiring','admin.security.governance_notifications.view','admin.security.governance_notifications.manage','admin.security.governance_notifications.resolve','admin.security.audit_exports.view','admin.security.audit_exports.generate','admin.security.audit_exports.download','admin.security.audit_exports.archive','admin.security.governance_escalation.run','admin.security.export_retention_jobs.view','admin.security.export_retention_jobs.dry_run','admin.security.export_retention_jobs.approve','admin.security.export_retention_jobs.execute','admin.security.export_retention_jobs.cancel','admin.security.notifications.sla_manage','admin.security.notifications.sla_check','admin.security.incidents.view','admin.security.incidents.manage','admin.security.incidents.resolve'];$map=['security_reviewer'=>['admin.security.retention.view','admin.security.retention.dry_run','admin.security.retention.approve','admin.security.file_scanner.test','admin.security.evidence_rescan.run'],'compliance_reviewer'=>['admin.security.retention.view','admin.security.retention.approve','admin.worker_payout_evidence.download'],'owner'=>$governance,'admin'=>$governance,'security_manager'=>$governance];foreach(array_unique(array_merge(...array_values($map))) as $p)Permission::findOrCreate($p,'web');foreach($map as $role=>$permissions)Role::findOrCreate($role,'web')->givePermissionTo($permissions);app(PermissionRegistrar::class)->forgetCachedPermissions();}
